    private boolean isAdDomain(String url) {
        String[] patterns = {"doubleclick.net","googleadservices.com","googlesyndication.com",
            "google-analytics.com","ads.youtube.com","adservice.google",
            "pagead2.googlesyndication.com","ad.doubleclick.net","static.doubleclick.net"};
        String l = url.toLowerCase();
        for (String p : patterns) if (l.contains(p)) return true;
        return false;
    }

    // ─── VIDEO LIST ────────────────────────────────────────
    private void setupVideoList() {
        videoList.setOnItemClickListener((parent, view, position, id) -> {
            if (position < videoUrls.size()) {
                playVideo(videoUrls.get(position));
            }
        });

        videoList.setOnItemLongClickListener((parent, view, position, id) -> {
            if (position < videoTitles.size()) {
                showVideoOptions(position);
                return true;
            }
            return false;
        });
