        for (LinearLayout nav : new LinearLayout[]{navHome, navSearch, navLibrary, navDownloads}) {
            TextView label = (TextView) nav.getChildAt(1);
            label.setTextColor(Color.parseColor("#888888"));
        }
    }

    private void highlightNav(LinearLayout nav) {
        TextView label = (TextView) nav.getChildAt(1);
        label.setTextColor(Color.parseColor("#FF0000"));
