        webView.setVisibility(View.VISIBLE);
        videoList.setVisibility(View.GONE);
        webView.loadUrl(url);
    }

    private void searchYouTube(String query) {
        if (query.isEmpty()) return;
        String url = "https://www.youtube-nocookie.com/results?search_query=" +
                     query.replace(" ", "+");
        webView.setVisibility(View.VISIBLE);
        videoList.setVisibility(View.GONE);
        webView.loadUrl(url);
    }

    private void addToPlaylist(int pos) {
        if (pos < videoTitles.size() && pos < videoUrls.size()) {
            playlistTitles.add(videoTitles.get(pos));
            playlistVideos.add(videoUrls.get(pos));
            Toast.makeText(this, "Added to Library!", Toast.LENGTH_SHORT).show();
        }
    }

