{"content": "package com.sovereign.client;

import android.annotation.SuppressLint;
import android.app.Activity;
import android.app.AlertDialog;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.graphics.Color;
import android.net.Uri;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.view.KeyEvent;
import android.view.View;
import android.view.ViewGroup;
import android.widget.BaseAdapter;
import android.widget.EditText;
import android.widget.HorizontalScrollView;
import android.widget.ImageButton;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.ListView;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;
import android.widget.VideoView;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.JsonParser;

import java.io.BufferedReader;
import java.io.DataOutputStream;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.URL;
import java.net.URLEncoder;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class YouTubeActivity extends Activity {

    // Backend - auto-started python server on localhost
    private static final String BASE = "http://127.0.0.1:8765";
    private static final String PYTHON_PATH = "/data/data/com.termux/files/usr/bin/python3";
    private static final String BACKEND_SCRIPT = "/data/data/com.termux/files/home/sovereign_agent/workspace/yt_backend.py";

    // Views
    private ListView videoList;
    private EditText searchInput;
    private ProgressBar progressBar;
    private LinearLayout playerContainer;
    private VideoView videoView;
    private TextView playerTitle, emptyText;
    private ImageButton playerClose, playerBack, searchBtn;
    private HorizontalScrollView chipScroll;
    private LinearLayout chipContainer;

    // Bottom nav
    private LinearLayout navHome, navSearch, navLibrary, navDownloads;
    private TextView navHomeLabel, navSearchLabel, navLibraryLabel, navDownloadsLabel;

    // State
    private List<VideoItem> videos = new ArrayList<>();
    private List<VideoItem> library = new ArrayList<>();
    private List<DownloadItem> downloads = new ArrayList<>();
    private String currentPage = "home";
    private VideoAdapter adapter;
    private Handler handler = new Handler(Looper.getMainLooper());
    private final Map<String, Bitmap> thumbCache = new HashMap<>();
    private boolean backendStarted = false;

    // Models
    static class VideoItem {
        String id, title, channel, durationStr, thumbnail, url, streamUrl;
        long duration;
    }
    static class DownloadItem {
        String name, path;
        double sizeMb;
    }

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_youtube);

        // Bind views
        videoList = findViewById(R.id.videoList);
        searchInput = findViewById(R.id.searchInput);
        progressBar = findViewById(R.id.progressBar);
        playerContainer = findViewById(R.id.playerContainer);
        videoView = findViewById(R.id.videoView);
        playerTitle = findViewById(R.id.playerTitle);
        playerClose = findViewById(R.id.playerClose);
        playerBack = findViewById(R.id.playerBack);
        searchBtn = findViewById(R.id.searchBtn);
        emptyText = findViewById(R.id.emptyText);
        chipScroll = findViewById(R.id.chipScroll);
        chipContainer = findViewById(R.id.chipContainer);

        navHome = findViewById(R.id.navHome);
        navSearch = findViewById(R.id.navSearch);
        navLibrary = findViewById(R.id.navLibrary);
        navDownloads = findViewById(R.id.navDownloads);
        navHomeLabel = findViewById(R.id.navHomeLabel);
        navSearchLabel = findViewById(R.id.navSearchLabel);
        navLibraryLabel = findViewById(R.id.navLibraryLabel);
        navDownloadsLabel = findViewById(R.id.navDownloadsLabel);

        adapter = new VideoAdapter();
        videoList.setAdapter(adapter);

        setupChips();
        setupNav();
        setupPlayer();

        searchInput.setOnEditorActionListener((v, actionId, event) -> {
            if (event != null && event.getKeyCode() == KeyEvent.KEYCODE_ENTER) {
                doSearch(searchInput.getText().toString().trim());
                return true;
            }
            return false;
        });
        searchBtn.setOnClickListener(v -> doSearch(searchInput.getText().toString().trim()));

        // Auto-start backend, then load trending
        emptyText.setText("Starting backend...");
        emptyText.setVisibility(View.VISIBLE);
        startBackend();
    }

    // ─── BACKEND AUTO-START ────────────────────────────────
    private void startBackend() {
        new Thread(() -> {
            // Check if backend already running
            if (pingBackend()) {
                backendStarted = true;
                handler.post(this::onBackendReady);
                return;
            }

            // Try to start python backend
            try {
                ProcessBuilder pb = new ProcessBuilder(PYTHON_PATH, BACKEND_SCRIPT);
                pb.redirectErrorStream(true);
                Process p = pb.start();
                p.getOutputStream().close();

                // Wait for backend to be ready (max 15 seconds)
                for (int i = 0; i < 30; i++) {
                    Thread.sleep(500);
                    if (pingBackend()) {
                        backendStarted = true;
                        handler.post(this::onBackendReady);
                        return;
                    }
                }
                // Backend failed to start
                handler.post(() -> {
                    emptyText.setText("Backend failed to start.\nMake sure Termux + yt-dlp installed.\nOr run: python3 " + BACKEND_SCRIPT);
                });
            } catch (Exception e) {
                handler.post(() -> {
                    emptyText.setText("Cannot start backend.\nTermux may not be installed.\n\nInstall Termux + run:\npip install yt-dlp requests");
                });
            }
        }).start();
    }

    private boolean pingBackend() {
        try {
            HttpURLConnection c = (HttpURLConnection) new URL(BASE + "/status").openConnection();
            c.setConnectTimeout(2000);
            c.setReadTimeout(2000);
            int code = c.getResponseCode();
            c.disconnect();
            return code == 200;
        } catch (Exception e) {
            return false;
        }
    }

    private void onBackendReady() {
        emptyText.setVisibility(View.GONE);
        showPage("home");
        loadTrending();
        Toast.makeText(this, "Backend ready!", Toast.LENGTH_SHORT).show();
    }

    // ─── ADAPTER ───────────────────────────────────────────
    class VideoAdapter extends BaseAdapter {
        @Override public int getCount() { return videos.size(); }
        @Override public Object getItem(int i) { return videos.get(i); }
        @Override public long getItemId(int i) { return i; }

        @Override
        public View getView(int pos, View convert, ViewGroup parent) {
            if (convert == null)
                convert = getLayoutInflater().inflate(R.layout.video_item, parent, false);

            VideoItem v = videos.get(pos);
            TextView title = convert.findViewById(R.id.title);
            TextView channel = convert.findViewById(R.id.channel);
            TextView duration = convert.findViewById(R.id.duration);
            ImageView thumb = convert.findViewById(R.id.thumb);

            title.setText(v.title);
            channel.setText(v.channel);
            duration.setText(v.durationStr);

            thumb.setImageBitmap(null);
            if (v.thumbnail != null) {
                Bitmap cached = thumbCache.get(v.id);
                if (cached != null) {
                    thumb.setImageBitmap(cached);
                } else {
                    loadThumb(v.id, v.thumbnail, thumb);
                }
            }
            return convert;
        }
    }

    private void loadThumb(String id, String url, ImageView target) {
        new Thread(() -> {
            try {
                HttpURLConnection c = (HttpURLConnection) new URL(url).openConnection();
                c.setConnectTimeout(5000);
                c.setReadTimeout(5000);
                InputStream is = c.getInputStream();
                Bitmap bmp = BitmapFactory.decodeStream(is);
                is.close();
                c.disconnect();
                if (bmp != null) {
                    thumbCache.put(id, bmp);
                    handler.post(() -> {
                        if (target != null) target.setImageBitmap(bmp);
                    });
                }
            } catch (Exception e) { /* ignore */ }
        }).start();
    }

    // ─── CHIPS ─────────────────────────────────────────────
    private void setupChips() {
        String[] chips = {"Trending", "Music", "Gaming", "News", "Live", "Movies",
                          "Comedy", "Sports", "Tech", "Cooking"};
        for (String chip : chips) {
            TextView tv = new TextView(this);
            tv.setText(chip);
            tv.setTextColor(Color.WHITE);
            tv.setBackgroundColor(Color.parseColor("#272727"));
            tv.setPadding(24, 8, 24, 8);
            tv.setTextSize(13);
            LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.WRAP_CONTENT, ViewGroup.LayoutParams.WRAP_CONTENT);
            lp.setMargins(6, 0, 6, 0);
            tv.setLayoutParams(lp);
            tv.setOnClickListener(v -> doSearch(chip));
            chipContainer.addView(tv);
        }
    }

    // ─── NAV ───────────────────────────────────────────────
    private void setupNav() {
        navHome.setOnClickListener(v -> { showPage("home"); loadTrending(); });
        navSearch.setOnClickListener(v -> {
            searchInput.requestFocus();
            searchInput.setText("");
        });
        navLibrary.setOnClickListener(v -> { showPage("library"); loadLibrary(); });
        navDownloads.setOnClickListener(v -> { showPage("downloads"); loadDownloads(); });
    }

    private void showPage(String page) {
        currentPage = page;
        playerContainer.setVisibility(View.GONE);

        navHomeLabel.setTextColor(Color.parseColor("#888888"));
        navSearchLabel.setTextColor(Color.parseColor("#888888"));
        navLibraryLabel.setTextColor(Color.parseColor("#888888"));
        navDownloadsLabel.setTextColor(Color.parseColor("#888888"));

        switch (page) {
            case "home":
                navHomeLabel.setTextColor(Color.parseColor("#FF0000"));
                chipScroll.setVisibility(View.VISIBLE);
                break;
            case "library":
                navLibraryLabel.setTextColor(Color.parseColor("#FF0000"));
                chipScroll.setVisibility(View.GONE);
                break;
            case "downloads":
                navDownloadsLabel.setTextColor(Color.parseColor("#FF0000"));
                chipScroll.setVisibility(View.GONE);
                break;
        }
    }

    // ─── PLAYER ────────────────────────────────────────────
    private void setupPlayer() {
        playerClose.setOnClickListener(v -> {
            videoView.stopPlayback();
            playerContainer.setVisibility(View.GONE);
        });
        playerBack.setOnClickListener(v -> {
            if (videoView.getDuration() > 0)
                videoView.seekTo(Math.max(0, videoView.getCurrentPosition() - 10000));
        });
    }

    @SuppressLint("SetTextI18n")
    private void playVideo(VideoItem item) {
        if (item.streamUrl != null && !item.streamUrl.isEmpty()) {
            startPlayback(item);
            return;
        }
        Toast.makeText(this, "Fetching stream...", Toast.LENGTH_SHORT).show();
        progressBar.setVisibility(View.VISIBLE);
        fetchStreamAndPlay(item);
    }

    private void fetchStreamAndPlay(VideoItem item) {
        new Thread(() -> {
            try {
                String resp = httpGet(BASE + "/video?id=" + item.id);
                JsonObject obj = JsonParser.parseString(resp).getAsJsonObject();
                if (obj.has("stream_url")) {
                    item.streamUrl = obj.get("stream_url").getAsString();
                }
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    if (item.streamUrl != null && !item.streamUrl.isEmpty()) {
                        startPlayback(item);
                    } else {
                        String err = obj.has("error") ? obj.get("error").getAsString() : "Stream not available";
                        Toast.makeText(this, err, Toast.LENGTH_LONG).show();
                    }
                });
            } catch (Exception e) {
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    Toast.makeText(this, "Error: " + e.getMessage(), Toast.LENGTH_SHORT).show();
                });
            }
        }).start();
    }

    @SuppressLint("SetTextI18n")
    private void startPlayback(VideoItem item) {
        playerTitle.setText(item.title);
        playerContainer.setVisibility(View.VISIBLE);
        videoView.setVisibility(View.VISIBLE);

        try {
            Uri uri = Uri.parse(item.streamUrl);
            videoView.setVideoURI(uri);
            videoView.setOnPreparedListener(mp -> {
                mp.setLooping(false);
                videoView.start();
            });
            videoView.setOnErrorListener((mp, what, extra) -> {
                Toast.makeText(this, "Playback error (stream may be expired)", Toast.LENGTH_LONG).show();
                return true;
            });
            videoView.setOnCompletionListener(mp -> {
                playerContainer.setVisibility(View.GONE);
            });
        } catch (Exception e) {
            Toast.makeText(this, "Error: " + e.getMessage(), Toast.LENGTH_SHORT).show();
        }
    }

    // ─── SEARCH ────────────────────────────────────────────
    private void doSearch(String query) {
        if (query.isEmpty()) return;
        if (!backendStarted) {
            Toast.makeText(this, "Backend not ready yet...", Toast.LENGTH_SHORT).show();
            return;
        }
        showPage("home");
        progressBar.setVisibility(View.VISIBLE);
        emptyText.setVisibility(View.GONE);

        new Thread(() -> {
            try {
                String resp = httpGet(BASE + "/search?q=" + URLEncoder.encode(query, "UTF-8"));
                JsonObject obj = JsonParser.parseString(resp).getAsJsonObject();
                List<VideoItem> results = parseVideos(obj);
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    videos.clear();
                    videos.addAll(results);
                    adapter.notifyDataSetChanged();
                    if (results.isEmpty()) {
                        emptyText.setText("No results for \"" + query + "\"");
                        emptyText.setVisibility(View.VISIBLE);
                    } else {
                        emptyText.setVisibility(View.GONE);
                    }
                });
            } catch (Exception e) {
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    emptyText.setText("Error: " + e.getMessage());
                    emptyText.setVisibility(View.VISIBLE);
                });
            }
        }).start();
    }

    private void loadTrending() {
        if (!backendStarted) return;
        progressBar.setVisibility(View.VISIBLE);
        emptyText.setVisibility(View.GONE);

        new Thread(() -> {
            try {
                String resp = httpGet(BASE + "/trending");
                JsonObject obj = JsonParser.parseString(resp).getAsJsonObject();
                List<VideoItem> results = parseVideos(obj);
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    videos.clear();
                    videos.addAll(results);
                    adapter.notifyDataSetChanged();
                    if (results.isEmpty()) {
                        emptyText.setText("Tap search or a chip to find videos");
                        emptyText.setVisibility(View.VISIBLE);
                    }
                });
            } catch (Exception e) {
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    emptyText.setText("Backend error. Try searching.");
                    emptyText.setVisibility(View.VISIBLE);
                });
            }
        }).start();
    }

    private void loadLibrary() {
        if (library.isEmpty()) {
            videos.clear();
            adapter.notifyDataSetChanged();
            emptyText.setText("No saved videos. Long-press a video to add.");
            emptyText.setVisibility(View.VISIBLE);
            return;
        }
        videos.clear();
        videos.addAll(library);
        adapter.notifyDataSetChanged();
        emptyText.setVisibility(View.GONE);
    }

    private void loadDownloads() {
        progressBar.setVisibility(View.VISIBLE);
        new Thread(() -> {
            try {
                String resp = httpGet(BASE + "/downloads");
                JsonObject obj = JsonParser.parseString(resp).getAsJsonObject();
                downloads.clear();
                if (obj.has("files")) {
                    JsonArray arr = obj.getAsJsonArray("files");
                    for (JsonElement el : arr) {
                        JsonObject f = el.getAsJsonObject();
                        DownloadItem d = new DownloadItem();
                        d.name = f.get("name").getAsString();
                        d.path = f.get("path").getAsString();
                        d.sizeMb = f.get("size_mb").getAsDouble();
                        downloads.add(d);
                    }
                }
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    videos.clear();
                    for (DownloadItem d : downloads) {
                        VideoItem vi = new VideoItem();
                        vi.id = d.path;
                        vi.title = d.name;
                        vi.channel = d.sizeMb + " MB";
                        vi.durationStr = "FILE";
                        vi.thumbnail = null;
                        vi.streamUrl = "file://" + d.path;
                        videos.add(vi);
                    }
                    adapter.notifyDataSetChanged();
                    if (downloads.isEmpty()) {
                        emptyText.setText("No downloads yet");
                        emptyText.setVisibility(View.VISIBLE);
                    }
                });
            } catch (Exception e) {
                handler.post(() -> {
                    progressBar.setVisibility(View.GONE);
                    emptyText.setText("Backend not running");
                    emptyText.setVisibility(View.VISIBLE);
                });
            }
        }).start();
    }

    // ─── VIDEO LIST INTERACTIONS ──────────────────────────
    @Override
    protected void onResume() {
        super.onResume();
        videoList.setOnItemClickListener((parent, view, pos, id) -> {
            if (pos < videos.size()) playVideo(videos.get(pos));
        });
        videoList.setOnItemLongClickListener((parent, view, pos, id) -> {
            if (pos < videos.size()) {
                showVideoOptions(pos);
                return true;
            }
            return false;
        });
    }

    private void showVideoOptions(int pos) {
        VideoItem v = videos.get(pos);
        String[] options = {"Play", "Add to Library", "Download", "Share URL"};
        new AlertDialog.Builder(this)
            .setTitle(v.title)
            .setItems(options, (dialog, which) -> {
                switch (which) {
                    case 0: playVideo(v); break;
                    case 1:
                        library.add(v);
                        Toast.makeText(this, "Added to Library!", Toast.LENGTH_SHORT).show();
                        break;
                    case 2: startDownload(v); break;
                    case 3: shareUrl(v.url); break;
                }
            })
            .show();
    }

    private void startDownload(VideoItem v) {
        new Thread(() -> {
            try {
                URL url = new URL(BASE + "/download");
                HttpURLConnection c = (HttpURLConnection) url.openConnection();
                c.setRequestMethod("POST");
                c.setRequestProperty("Content-Type", "application/json");
                c.setDoOutput(true);
                String body = "{\"url\":\"" + v.url + "\",\"title\":\"" + v.title.replace("\"","") + "\"}";
                DataOutputStream out = new DataOutputStream(c.getOutputStream());
                out.writeBytes(body);
                out.flush();
                out.close();
                int code = c.getResponseCode();
                c.disconnect();
                handler.post(() -> Toast.makeText(this,
                    code == 200 ? "Download started!" : "Download failed",
                    Toast.LENGTH_SHORT).show());
            } catch (Exception e) {
                handler.post(() -> Toast.makeText(this, "Download error", Toast.LENGTH_SHORT).show());
            }
        }).start();
    }

    private void shareUrl(String url) {
        if (url == null) return;
        Intent share = new Intent(Intent.ACTION_SEND);
        share.setType("text/plain");
        share.putExtra(Intent.EXTRA_TEXT, url);
        startActivity(Intent.createChooser(share, "Share video"));
    }

    // ─── HTTP UTILS ────────────────────────────────────────
    private String httpGet(String urlStr) throws Exception {
        URL url = new URL(urlStr);
        HttpURLConnection c = (HttpURLConnection) url.openConnection();
        c.setConnectTimeout(15000);
        c.setReadTimeout(15000);
        BufferedReader r = new BufferedReader(new InputStreamReader(c.getInputStream()));
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = r.readLine()) != null) sb.append(line);
        r.close();
        c.disconnect();
        return sb.toString();
    }

    private List<VideoItem> parseVideos(JsonObject obj) {
        List<VideoItem> list = new ArrayList<>();
        if (obj.has("results")) {
            JsonArray arr = obj.getAsJsonArray("results");
            for (JsonElement el : arr) {
                JsonObject v = el.getAsJsonObject();
                VideoItem item = new VideoItem();
                item.id = v.has("id") ? v.get("id").getAsString() : "";
                item.title = v.has("title") ? v.get("title").getAsString() : "";
                item.channel = v.has("channel") ? v.get("channel").getAsString() : "";
                item.duration = v.has("duration") && !v.get("duration").isJsonNull()
                    ? v.get("duration").getAsLong() : 0;
                item.durationStr = v.has("duration_str") ? v.get("duration_str").getAsString() : "--:--";
                item.thumbnail = v.has("thumbnail") ? v.get("thumbnail").getAsString() : null;
                item.url = v.has("url") ? v.get("url").getAsString() : "";
                list.add(item);
            }
        }
        return list;
    }

    @Override
    public void onBackPressed() {
        if (playerContainer.getVisibility() == View.VISIBLE) {
            videoView.stopPlayback();
            playerContainer.setVisibility(View.GONE);
        } else {
            super.onBackPressed();
        }
    }
}
